const ago = (ts) => {
  if (!ts) return "—";
  const m = Math.floor((Date.now() - (ts.seconds ? ts.seconds * 1e3 : ts)) / 6e4);
  return m < 1 ? "Just now" : m < 60 ? `${m}m ago` : m < 1440 ? `${Math.floor(m / 60)}h ago` : `${Math.floor(m / 1440)}d ago`;
};
const dstr = (ts) => {
  if (!ts) return "—";
  return new Date(ts.seconds ? ts.seconds * 1e3 : ts).toLocaleDateString("en-GH", { day: "numeric", month: "short", year: "numeric" });
};
